    #[derive(Debug, Clone, PartialEq, Eq)]
    struct TestSettings {
        schema_version: u32,
        name: String,
    }

    impl TomlDocument for TestSettings {
        fn encode_toml(&self) -> FileStoreResult<String> {
            Ok(format!(
                "schema_version = {}\nname = \"{}\"\n",
                self.schema_version, self.name
            ))
        }

        fn decode_toml(source: &str) -> Result<Self, TomlParseError> {
            let values = parse_flat_toml(source)?;
            let schema_version = values
                .get("schema_version")
                .ok_or_else(|| TomlParseError::single(1, 1, "missing schema_version"))?
                .parse::<u32>()
                .map_err(|_| TomlParseError::single(1, 18, "invalid schema_version"))?;
            let name = values
                .get("name")
                .ok_or_else(|| TomlParseError::single(1, 1, "missing name"))?
                .to_string();
            Ok(Self {
                schema_version,
                name,
            })
        }
    }

    #[test]
    fn toml_roundtrip_writes_and_reads_one_file() {
        let temp = tempdir().expect("temp dir");
        let store = FileStore::new(temp.path());
        let settings = TestSettings {
            schema_version: 1,
            name: "default".to_string(),
        };

        store
            .write_toml("settings.toml", &settings)
            .expect("write settings");
        let loaded = store
            .read_toml::<TestSettings>("settings.toml")
            .expect("read settings");

        assert_eq!(loaded, settings);
    }

