        let temp = tempdir().expect("temp dir");
        let store = FileStore::new(temp.path());
        fs::write(temp.path().join("settings.toml"), "schema_version =\n").expect("bad toml");

        let error = store
            .read_toml::<TestSettings>("settings.toml")
            .expect_err("bad TOML should fail");

        match error {
            FileStoreError::TomlParse(parse_error) => {
                let diagnostics = parse_error.diagnostics();
                assert_eq!(diagnostics.len(), 1);
                assert_eq!(
                    diagnostics[0].path.as_deref(),
                    Some(Path::new("settings.toml"))
                );
                assert_eq!(diagnostics[0].line, 1);
            }
            other => panic!("expected TOML parse error, got {other:?}"),
        }
    }

    #[test]
    fn backup_existing_file_preserves_previous_contents() {
        let temp = tempdir().expect("temp dir");
        let store = FileStore::new(temp.path());
        store
            .atomic_write("settings.toml", b"schema_version = 1\nname = \"old\"\n")
            .expect("write original");

        let backup_path = store
            .backup_existing("settings.toml", "backups/change-1")
            .expect("backup")
            .expect("backup path");
        store
            .atomic_write("settings.toml", b"schema_version = 1\nname = \"new\"\n")
            .expect("write replacement");

        assert_eq!(
            fs::read_to_string(&backup_path).expect("backup source"),
            "schema_version = 1\nname = \"old\"\n"
        );
        assert_eq!(
            fs::read_to_string(temp.path().join("settings.toml")).expect("current source"),
            "schema_version = 1\nname = \"new\"\n"
        );
        assert_eq!(
            backup_path,
            temp.path()
                .join("backups")
                .join("change-1")
                .join("settings.toml")
        );
