    #[test]
    fn read_storage_manifest_defaults_when_missing() {
        let temp = tempdir().expect("temp dir");
        let store = FileStore::new(temp.path());

        let manifest = store.read_storage_manifest().expect("default manifest");

        assert_eq!(manifest, StorageManifest::new());
        assert!(!temp.path().join("storage-manifest.toml").exists());
    }

    #[test]
    fn lock_file_rejects_second_holder_until_released() {
        let temp = tempdir().expect("temp dir");
        let store = FileStore::new(temp.path());

        let first_lock = store.acquire_lock().expect("first lock");
        let second_error = store.acquire_lock().expect_err("second lock should fail");

        assert!(matches!(second_error, FileStoreError::Locked(_)));

        drop(first_lock);
        store.acquire_lock().expect("lock released");
    }

    #[test]
    fn change_set_applies_multiple_files_and_persists_manifest() {
        let temp = tempdir().expect("temp dir");
        let store = FileStore::new(temp.path());
        store
            .atomic_write("settings.toml", b"schema_version = 1\nname = \"old\"\n")
            .expect("write settings");
        store
            .atomic_write(
                "profiles/default.toml",
                b"schema_version = 1\nname = \"old-profile\"\n",
            )
            .expect("write profile");

        let manifest = store
            .apply_change_set(
                "change-2",
                "2026-06-24T10:01:00+08:00",
                vec![
                    FileStoreChange::new(
                        "settings.toml",
                        b"schema_version = 1\nname = \"new\"\n".to_vec(),
                    )
                    .expect("settings change"),
                    FileStoreChange::new(
                        "profiles/default.toml",
                        b"schema_version = 1\nname = \"new-profile\"\n".to_vec(),
                    )
                    .expect("profile change"),
                ],
            )
            .expect("apply change set");
        let loaded_manifest = store.read_storage_manifest().expect("read manifest");
        let change_set = loaded_manifest.change_set("change-2").expect("change set");

        assert_eq!(loaded_manifest, manifest);
        assert_eq!(change_set.status, ChangeSetStatus::Applied);
        assert_eq!(
            fs::read_to_string(temp.path().join("settings.toml")).expect("settings"),
            "schema_version = 1\nname = \"new\"\n"
        );
        assert_eq!(
            fs::read_to_string(temp.path().join("profiles/default.toml")).expect("profile"),
            "schema_version = 1\nname = \"new-profile\"\n"
        );
        assert_eq!(
            fs::read_to_string(temp.path().join("backups/change-2/settings.toml"))
                .expect("settings backup"),
            "schema_version = 1\nname = \"old\"\n"
        );
        assert_eq!(
            fs::read_to_string(temp.path().join("backups/change-2/profiles/default.toml"))
                .expect("profile backup"),
            "schema_version = 1\nname = \"old-profile\"\n"
        );
    }

    #[test]
    fn restore_change_set_recovers_partial_write_from_backup() {
        let temp = tempdir().expect("temp dir");
        let store = FileStore::new(temp.path());
        store
            .atomic_write("settings.toml", b"schema_version = 1\nname = \"old\"\n")
            .expect("write settings");
        fs::write(temp.path().join("profiles"), "not a directory").expect("write blocking file");

        let apply_error = store
            .apply_change_set(
                "change-3",
                "2026-06-24T10:02:00+08:00",
                vec![
                    FileStoreChange::new(
                        "settings.toml",
                        b"schema_version = 1\nname = \"new\"\n".to_vec(),
                    )
                    .expect("settings change"),
                    FileStoreChange::new(
                        "profiles/default.toml",
                        b"schema_version = 1\nname = \"profile\"\n".to_vec(),
                    )
                    .expect("profile change"),
                ],
            )
            .expect_err("second write should fail");
        let failed_manifest = store.read_storage_manifest().expect("failed manifest");
        let failed_change_set = failed_manifest
            .change_set("change-3")
            .expect("failed change");

        assert!(matches!(apply_error, FileStoreError::Io(_)));
        assert_eq!(failed_change_set.status, ChangeSetStatus::Failed);
        assert!(failed_manifest.repair_state.is_some());
        assert_eq!(
            fs::read_to_string(temp.path().join("settings.toml")).expect("partial settings"),
            "schema_version = 1\nname = \"new\"\n"
        );

        let repaired_manifest = store
            .restore_change_set("change-3", "2026-06-24T10:02:01+08:00")
            .expect("restore change set");
        let repaired_change_set = repaired_manifest
            .change_set("change-3")
            .expect("repaired change");

        assert_eq!(repaired_change_set.status, ChangeSetStatus::Repaired);
        assert!(repaired_manifest.repair_state.is_none());
        assert_eq!(
            fs::read_to_string(temp.path().join("settings.toml")).expect("restored settings"),
            "schema_version = 1\nname = \"old\"\n"
        );
    }

    fn parse_flat_toml(source: &str) -> Result<BTreeMap<String, String>, TomlParseError> {
        let mut values = BTreeMap::new();
        for (index, line) in source.lines().enumerate() {
            let line_number = index + 1;
            let trimmed = line.trim();
            if trimmed.is_empty() || trimmed.starts_with('#') {
                continue;
            }
            let Some((raw_key, raw_value)) = trimmed.split_once('=') else {
                return Err(TomlParseError::single(line_number, 1, "missing '='"));
            };
            let key = raw_key.trim();
            let value = raw_value.trim();
            if value.is_empty() {
                return Err(TomlParseError::single(
                    line_number,
                    raw_key.len() + 2,
                    "missing value",
                ));
            }
            let value = value
                .strip_prefix('"')
                .and_then(|next| next.strip_suffix('"'))
                .unwrap_or(value)
                .to_string();
            values.insert(key.to_string(), value);
        }
        Ok(values)
    }
}

//! File storage manifest model.
//!
//! @author kongweiguang

use serde::{Deserialize, Serialize};

pub const STORAGE_MANIFEST_SCHEMA_VERSION: u32 = 1;

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct StorageManifest {
    pub schema_version: u32,
    pub active_change_set_id: Option<String>,
    pub last_applied_change_set_id: Option<String>,
    pub repair_state: Option<ManifestRepairState>,
    pub change_sets: Vec<ManifestChangeSet>,
}

impl Default for StorageManifest {
    fn default() -> Self {
        Self::new()
    }
}

impl StorageManifest {
    pub fn new() -> Self {
        Self {
            schema_version: STORAGE_MANIFEST_SCHEMA_VERSION,
            active_change_set_id: None,
            last_applied_change_set_id: None,
            repair_state: None,
            change_sets: Vec::new(),
        }
    }

    pub fn begin_change_set(
        &mut self,
        id: impl Into<String>,
        started_at: impl Into<String>,
        touched_files: Vec<String>,
    ) {
        let id = id.into();
        self.active_change_set_id = Some(id.clone());
        self.change_sets.push(ManifestChangeSet {
            id,
            status: ChangeSetStatus::Started,
            started_at: started_at.into(),
            completed_at: None,
            touched_files,
            backup_dir: None,
            error: None,
        });
    }

    pub fn mark_applied(&mut self, id: &str, completed_at: impl Into<String>) {
        let completed_at = completed_at.into();
        if let Some(change_set) = self.change_sets.iter_mut().find(|item| item.id == id) {
            change_set.status = ChangeSetStatus::Applied;
            change_set.completed_at = Some(completed_at);
            change_set.error = None;
        }
        self.active_change_set_id = None;
        self.last_applied_change_set_id = Some(id.to_string());
        self.repair_state = None;
    }

    pub fn set_backup_dir(&mut self, id: &str, backup_dir: impl Into<String>) {
        if let Some(change_set) = self.change_sets.iter_mut().find(|item| item.id == id) {
            change_set.backup_dir = Some(backup_dir.into());
        }
    }

    pub fn mark_failed(
        &mut self,
        id: &str,
        completed_at: impl Into<String>,
        error: impl Into<String>,
    ) {
        let completed_at = completed_at.into();
        let error = error.into();
        if let Some(change_set) = self.change_sets.iter_mut().find(|item| item.id == id) {
            change_set.status = ChangeSetStatus::Failed;
            change_set.completed_at = Some(completed_at.clone());
            change_set.error = Some(error.clone());
        }
        if self.active_change_set_id.as_deref() == Some(id) {
            self.active_change_set_id = None;
        }
        self.repair_state = Some(ManifestRepairState {
            change_set_id: id.to_string(),
            reason: error,
            detected_at: completed_at,
        });
    }

    pub fn mark_repaired(&mut self, id: &str, completed_at: impl Into<String>) {
        let completed_at = completed_at.into();
        if let Some(change_set) = self.change_sets.iter_mut().find(|item| item.id == id) {
            change_set.status = ChangeSetStatus::Repaired;
            change_set.completed_at = Some(completed_at);
            change_set.error = None;
        }
        if self.active_change_set_id.as_deref() == Some(id) {
            self.active_change_set_id = None;
        }
        if self
            .repair_state
            .as_ref()
            .map(|state| state.change_set_id.as_str())
            == Some(id)
        {
            self.repair_state = None;
        }
    }

    pub fn change_set(&self, id: &str) -> Option<&ManifestChangeSet> {
        self.change_sets.iter().find(|item| item.id == id)
    }
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct ManifestChangeSet {
    pub id: String,
    pub status: ChangeSetStatus,
    pub started_at: String,
    pub completed_at: Option<String>,
    pub touched_files: Vec<String>,
    pub backup_dir: Option<String>,
    pub error: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum ChangeSetStatus {
    Started,
    Applied,
    Failed,
    Repaired,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct ManifestRepairState {
    pub change_set_id: String,
    pub reason: String,
    pub detected_at: String,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn manifest_tracks_backup_failure_and_repair_lifecycle() {
        let mut manifest = StorageManifest::new();

        manifest.begin_change_set(
            "change-1",
            "2026-06-24T09:00:00+08:00",
            vec!["settings.toml".to_owned()],
        );
        manifest.set_backup_dir("change-1", "backups/change-1");
        manifest.mark_failed("change-1", "2026-06-24T09:00:01+08:00", "replace failed");

        assert_eq!(manifest.active_change_set_id, None);
        assert_eq!(
            manifest.repair_state,
            Some(ManifestRepairState {
                change_set_id: "change-1".to_owned(),
                reason: "replace failed".to_owned(),
                detected_at: "2026-06-24T09:00:01+08:00".to_owned(),
            })
        );
        assert_eq!(
            manifest.change_sets[0].backup_dir.as_deref(),
            Some("backups/change-1")
        );
        assert_eq!(manifest.change_sets[0].status, ChangeSetStatus::Failed);

        manifest.mark_repaired("change-1", "2026-06-24T09:00:02+08:00");

        assert_eq!(manifest.repair_state, None);
        assert_eq!(manifest.change_sets[0].status, ChangeSetStatus::Repaired);
        assert_eq!(manifest.change_sets[0].error, None);
    }

    #[test]
    fn manifest_clears_active_change_set_after_success() {
        let mut manifest = StorageManifest::new();
        manifest.begin_change_set(
            "change-2",
            "2026-06-24T09:00:00+08:00",
            vec!["profiles/default.toml".to_owned()],
        );

        manifest.mark_applied("change-2", "2026-06-24T09:00:01+08:00");

        assert_eq!(manifest.active_change_set_id, None);
        assert_eq!(
            manifest.last_applied_change_set_id.as_deref(),
            Some("change-2")
        );
        assert_eq!(manifest.change_sets[0].status, ChangeSetStatus::Applied);
    }
}
